const e=JSON.parse(`{"key":"v-2134b2d6","path":"/vanblog/%E5%86%85%E7%BD%91%E7%A9%BF%E9%80%8F%E5%B7%A5%E5%85%B7%E2%80%94%E2%80%94Frp%E5%AE%89%E8%A3%85%E4%B8%8E%E4%BD%BF%E7%94%A8%E6%95%99%E7%A8%8B.html","title":"简介","lang":"zh-CN","frontmatter":{"description":"简介 Frp是一个高性能的内网穿透反向代理应用，可以将内网服务访问端口映射到公网机器指定端口上，这样便可以在公网环境下访问到内网的服务,包括但不限于： 各类web服务(个人网站、文件共享等) SSH 远程桌面 ... 通过它，你可以自由访问家中的电脑、路由器、摄像头等各种设备。 基本原理 如下是frp的基本原理图，其中下方的虚线框是位于内网机器上的各类服务，中间的椭圆框是拥有公网IP的机器，上方的圆角矩形框是位于公网环境下的普通用户。可以看到，用户能够访问到内网服务都是要通过中间的公网机器中转来实现的。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/vanblog/%E5%86%85%E7%BD%91%E7%A9%BF%E9%80%8F%E5%B7%A5%E5%85%B7%E2%80%94%E2%80%94Frp%E5%AE%89%E8%A3%85%E4%B8%8E%E4%BD%BF%E7%94%A8%E6%95%99%E7%A8%8B.html"}],["meta",{"property":"og:site_name","content":"Kevin2li's Blog"}],["meta",{"property":"og:title","content":"简介"}],["meta",{"property":"og:description","content":"简介 Frp是一个高性能的内网穿透反向代理应用，可以将内网服务访问端口映射到公网机器指定端口上，这样便可以在公网环境下访问到内网的服务,包括但不限于： 各类web服务(个人网站、文件共享等) SSH 远程桌面 ... 通过它，你可以自由访问家中的电脑、路由器、摄像头等各种设备。 基本原理 如下是frp的基本原理图，其中下方的虚线框是位于内网机器上的各类服务，中间的椭圆框是拥有公网IP的机器，上方的圆角矩形框是位于公网环境下的普通用户。可以看到，用户能够访问到内网服务都是要通过中间的公网机器中转来实现的。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-05-22T06:31:47.000Z"}],["meta",{"property":"article:author","content":"Kevin2li"}],["meta",{"property":"article:modified_time","content":"2023-05-22T06:31:47.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"简介\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-05-22T06:31:47.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Kevin2li\\",\\"url\\":\\"https://blog.kevin2li.top\\"}]}"]]},"headers":[{"level":2,"title":"服务化","slug":"服务化","link":"#服务化","children":[{"level":3,"title":"客户端服务配置","slug":"客户端服务配置","link":"#客户端服务配置","children":[]},{"level":3,"title":"服务端服务配置","slug":"服务端服务配置","link":"#服务端服务配置","children":[]}]},{"level":2,"title":"域名访问","slug":"域名访问","link":"#域名访问","children":[]}],"git":{"createdTime":1684730003000,"updatedTime":1684737107000,"contributors":[{"name":"kevin2li","email":"kevin2li@qq.com","commits":3}]},"readingTime":{"minutes":6.26,"words":1878},"filePathRelative":"vanblog/内网穿透工具——Frp安装与使用教程.md","localizedDate":"2023年5月22日","excerpt":"<h1> 简介</h1>\\n<p>Frp是一个高性能的内网穿透反向代理应用，可以将内网服务访问端口映射到公网机器指定端口上，这样便可以在公网环境下访问到内网的服务,包括但不限于：</p>\\n<ul>\\n<li>各类web服务(个人网站、文件共享等)</li>\\n<li>SSH</li>\\n<li>远程桌面</li>\\n<li>...</li>\\n</ul>\\n<p>通过它，你可以自由访问家中的电脑、路由器、摄像头等各种设备。</p>\\n<h1> 基本原理</h1>\\n<p>如下是frp的基本原理图，其中下方的虚线框是位于内网机器上的各类服务，中间的椭圆框是拥有公网IP的机器，上方的圆角矩形框是位于公网环境下的普通用户。可以看到，用户能够访问到内网服务都是要通过中间的公网机器中转来实现的。</p>\\n<figure><img src=\\"https://minio.kevin2li.top/image-bed/vanblog/img/530fc52d6aed332e6c281b8cdc6f9187.20221019102104.png\\" alt=\\"\\" tabindex=\\"0\\" loading=\\"lazy\\"><figcaption></figcaption></figure>\\n","autoDesc":true}`);export{e as data};
